// ── Filtrar reseñas nuevas y formatearlas para Supabase ──────

// Reseñas recibidas de GBP
const gbpResponse = $('GET Reviews (GBP API)').first().json;

if (gbpResponse.error) {
  const msg = gbpResponse.error.message || JSON.stringify(gbpResponse.error);
  // Si es error de quota o permisos, loguear y detener sin fallar el workflow
  if (msg.includes('PERMISSION_DENIED') || msg.includes('quota') || msg.includes('403')) {
    console.log('[GBP] API restringida o quota agotada:', msg);
    return []; // detiene el workflow limpiamente
  }
  throw new Error('GBP API error: ' + msg);
}

const gbpReviews = gbpResponse.reviews || [];

// IDs ya guardados en Supabase
const existingRows = $input.all();
const existingIds  = new Set(existingRows.map(r => r.json.review_id).filter(Boolean));

// Mapeo estrellas
const STAR_MAP = { ONE: 1, TWO: 2, THREE: 3, FOUR: 4, FIVE: 5 };

// Filtrar solo nuevas y formatear
const newReviews = gbpReviews
  .filter(r => r.reviewId && !existingIds.has(r.reviewId))
  .map(r => ({
    review_id:    r.reviewId,
    author:       r.reviewer?.displayName || 'Anónimo',
    rating:       STAR_MAP[r.starRating]  || 5,
    text:         r.comment              || '',
    date:         r.createTime           || r.updateTime || new Date().toISOString(),
    status:       r.reviewReply ? 'published' : 'pending',
    draft_response:     '',
    published_response: r.reviewReply?.comment || '',
    location_id:  $('Config').first().json.GBP_LOCATION_ID
  }));

console.log(`[GBP Sync] Total GBP: ${gbpReviews.length} | Ya en SB: ${existingIds.size} | Nuevas: ${newReviews.length}`);

return newReviews.map(r => ({ json: r }));
